[
    {"path": "bravely-default-2-trainer/BravelyDefault2Trainer.csproj", "content": "<Project Sdk=\"Microsoft.NET.Sdk\">\n  <PropertyGroup>\n    <OutputType>Exe</OutputType>\n    <TargetFramework>net8.0</TargetFramework>\n    <ImplicitUsings>enable</ImplicitUsings>\n    <Nullable>enable</Nullable>\n  </PropertyGroup>\n  <ItemGroup>\n    <PackageReference Include=\"System.Management\" Version=\"8.0.0\" />\n    <PackageReference Include=\"Newtonsoft.Json\" Version=\"13.0.3\" />\n  </ItemGroup>\n</Project>"},
    {"path": "bravely-default-2-trainer/Program.cs", "content": "using System;\nusing System.Threading;\nusing BravelyDefault2Trainer.Memory;\nusing BravelyDefault2Trainer.UI;\n\nnamespace BravelyDefault2Trainer\n{\n    /// <summary>\n    /// Main entry point for the Bravely Default II Trainer.\n    /// Provides real-time memory editing for game values like HP, MP, JP, and Gold.\n    /// </summary>\n    class Program\n    {\n        static void Main(string[] args)\n        {\n            Console.Title = \"Bravely Default II Trainer v1.0\";\n            Console.WriteLine(\"=== Bravely Default II Trainer ===\");\n            Console.WriteLine(\"Attaching to process...\");\n\n            var processManager = new ProcessManager(\"BravelyDefaultII\");\n            if (!processManager.Attach())\n            {\n                Console.WriteLine(\"Failed to attach to Bravely Default II process. Ensure the game is running.\");\n                return;\n            }\n\n            var memoryEditor = new MemoryEditor(processManager);\n            var consoleUI = new ConsoleUI(memoryEditor);\n\n            Console.WriteLine(\"Attached successfully! Use the menu to modify game values.\");\n            consoleUI.Run();\n        }\n    }\n}"},
    {"path": "bravely-default-2-trainer/Memory/ProcessManager.cs", "content": "using System;\nusing System.Diagnostics;\nusing System.Linq;\n\nnamespace BravelyDefault2Trainer.Memory\n{\n    /// <summary>\n    /// Manages attachment to the Bravely Default II process for memory operations.\n    /// </summary>\n    public class ProcessManager\n    {\n        private readonly string _processName;\n        private Process? _process;\n\n        public ProcessManager(string processName)\n        {\n            _processName = processName;\n        }\n\n        /// <summary>\n        /// Attaches to the game process by name.\n        /// </summary>\n        /// <returns>True if attachment succeeded.</returns>\n        public bool Attach()\n        {\n            var processes = Process.GetProcessesByName(_processName);\n            if (processes.Length == 0)\n            {\n                return false;\n            }\n\n            _process = processes.FirstOrDefault(p => !p.HasExited);\n            return _process != null;\n        }\n\n        /// <summary>\n        /// Gets the base address of the main module.\n        /// </summary>\n        public IntPtr BaseAddress => _process?.MainModule?.BaseAddress ?? IntPtr.Zero;\n\n        /// <summary>\n        /// Reads bytes from process memory at a given offset.\n        /// </summary>\n        public byte[] ReadMemory(int offset, int size)\n        {\n            if (_process == null || _process.HasExited)\n                throw new InvalidOperationException(\"Process not attached or exited.\");\n\n            byte[] buffer = new byte[size];\n            using var handle = System.Runtime.InteropServices.PInvoke.Kernel32.OpenProcess(\n                System.Runtime.InteropServices.PInvoke.Kernel32.ProcessAccessFlags.VMRead |\n                System.Runtime.InteropServices.PInvoke.Kernel32.ProcessAccessFlags.VMWrite,\n                false, _process.Id);\n\n            if (handle.IsInvalid)\n                throw new InvalidOperationException(\"Failed to open process handle.\");\n\n            IntPtr baseAddr = IntPtr.Add(BaseAddress, offset);\n            if (!System.Runtime.InteropServices.PInvoke.Kernel32.ReadProcessMemory(\n                handle, baseAddr, buffer, size, out _))\n            {\n                throw new InvalidOperationException($\"Failed to read memory at offset 0x{offset:X}.\");\n            }\n\n            return buffer;\n        }\n\n        /// <summary>\n        /// Writes bytes to process memory at a given offset.\n        /// </summary>\n        public void WriteMemory(int offset, byte[] data)\n        {\n            if (_process == null || _process.HasExited)\n                throw new InvalidOperationException(\"Process not attached or exited.\");\n\n            using var handle = System.Runtime.InteropServices.PInvoke.Kernel32.OpenProcess(\n                System.Runtime.InteropServices.PInvoke.Kernel32.ProcessAccessFlags.VMWrite,\n                false, _process.Id);\n\n            if (handle.IsInvalid)\n                throw new InvalidOperationException(\"Failed to open process handle.\");\n\n            IntPtr baseAddr = IntPtr.Add(BaseAddress, offset);\n            if (!System.Runtime.InteropServices.PInvoke.Kernel32.WriteProcessMemory(\n                handle, baseAddr, data, data.Length, out _))\n            {\n                throw new InvalidOperationException($\"Failed to write memory at offset 0x{offset:X}.\");\n            }\n        }\n    }\n}"},
    {"path": "bravely-default-2-trainer/Memory/MemoryEditor.cs", "content": "using System;\nusing System.Text;\n\nnamespace BravelyDefault2Trainer.Memory\n{\n    /// <summary>\n    /// Provides high-level memory editing functions for Bravely Default II.\n    /// Offsets are based on common patterns (may vary by game version).\n    /// </summary>\n    public class MemoryEditor\n    {\n        private readonly ProcessManager _processManager;\n\n        // Example offsets (replace with actual scanned offsets for your game version)\n        private const int HpOffset = 0x01234560;\n        private const int MpOffset = 0x01234564;\n        private const int JpOffset = 0x01234580;\n        private const int GoldOffset = 0x012345A0;\n        private const int MaxHpOffset = 0x01234568;\n\n        public MemoryEditor(ProcessManager processManager)\n        {\n            _processManager = processManager;\n        }\n\n        /// <summary>\n        /// Gets the current HP value as a 32-bit integer.\n        /// </summary>\n        public int GetCurrentHp()\n        {\n            byte[] data = _processManager.ReadMemory(HpOffset, 4);\n            return BitConverter.ToInt32(data, 0);\n        }\n\n        /// <summary>\n        /// Sets HP to a given value (clamped to max HP).\n        /// </summary>\n        public void SetHp(int value)\n        {\n            int maxHp = GetMaxHp();\n            int clamped = Math.Min(value, maxHp);\n            byte[] data = BitConverter.GetBytes(clamped);\n            _processManager.WriteMemory(HpOffset, data);\n        }\n\n        /// <summary>\n        /// Infinitely refills HP to max (for God Mode).\n        /// </summary>\n        public void SetInfiniteHp()\n        {\n            int maxHp = GetMaxHp();\n            byte[] data = BitConverter.GetBytes(maxHp);\n            _processManager.WriteMemory(HpOffset, data);\n        }\n\n        /// <summary>\n        /// Gets the current MP value.\n        /// </summary>\n        public int GetCurrentMp()\n        {\n            byte[] data = _processManager.ReadMemory(MpOffset, 4);\n            return BitConverter.ToInt32(data, 0);\n        }\n\n        /// <summary>\n        /// Sets MP to a given value.\n        /// </summary>\n        public void SetMp(int value)\n        {\n            byte[] data = BitConverter.GetBytes(value);\n            _processManager.WriteMemory(MpOffset, data);\n        }\n\n        /// <summary>\n        /// Gets the current JP (Job Points).\n        /// </summary>\n        public int GetCurrentJp()\n        {\n            byte[] data = _processManager.ReadMemory(JpOffset, 4);\n            return BitConverter.ToInt32(data, 0);\n        }\n\n        /// <summary>\n        /// Sets JP to a given value.\n        /// </summary>\n        public void SetJp(int value)\n        {\n            byte[] data = BitConverter.GetBytes(value);\n            _processManager.WriteMemory(JpOffset, data);\n        }\n\n        /// <summary>\n        /// Gets the current Gold amount.\n        /// </summary>\n        public int GetCurrentGold()\n        {\n            byte[] data = _processManager.ReadMemory(GoldOffset, 4);\n            return BitConverter.ToInt32(data, 0);\n        }\n\n        /// <summary>\n        /// Sets Gold to a given value.\n        /// </summary>\n        public void SetGold(int value)\n        {\n            byte[] data = BitConverter.GetBytes(value);\n            _processManager.WriteMemory(GoldOffset, data);\n        }\n\n        /// <summary>\n        /// Gets the max HP value.\n        /// </summary>\n        public int GetMaxHp()\n        {\n            byte[] data = _processManager.ReadMemory(MaxHpOffset, 4);\n            return BitConverter.ToInt32(data, 0);\n        }\n    }\n}"},
    {"path": "bravely-default-2-trainer/UI/ConsoleUI.cs", "content": "using System;\nusing BravelyDefault2Trainer.Memory;\n\nnamespace BravelyDefault2Trainer.UI\n{\n    /// <summary>\n    /// Simple console-based user interface for the trainer.\n    /// Allows the user to read and modify game values interactively.\n    /// </summary>\n    public class ConsoleUI\n    {\n        private readonly MemoryEditor _memoryEditor;\n\n        public ConsoleUI(MemoryEditor memoryEditor)\n        {\n            _memoryEditor = memoryEditor;\n        }\n\n        /// <summary>\n        /// Runs the main menu loop.\n        /// </summary>\n        public void Run()\n        {\n            bool running = true;\n            while (running)\n            {\n                DisplayMenu();\n                string? input = Console.ReadLine()?.Trim().ToLower();\n                switch (input)\n                {\n                    case \"1\":\n                        ShowCurrentValues();\n                        break;\n                    case \"2\":\n                        SetHpMenu();\n                        break;\n                    case \"3\":\n                        SetMpMenu();\n                        break;\n                    case \"4\":\n                        SetJpMenu();\n                        break;\n                    case \"5\":\n                        SetGoldMenu();\n                        break;\n                    case \"6\":\n                        _memoryEditor.SetInfiniteHp();\n                        Console.WriteLine(\"HP set to max (God Mode effect).\");\n                        break;\n                    case \"7\":\n                        Console.WriteLine(\"Exiting trainer...\");\n                        running = false;\n                        break;\n                    default:\n                        Console.WriteLine(\"Invalid option. Please try again.\");\n                        break;\n                }\n\n                if (running)\n                {\n                    Console.WriteLine(\"\\nPress any key to continue...\");\n                    Console.ReadKey();\n                }\n            }\n        }\n\n        private void DisplayMenu()\n        {\n            Console.Clear();\n            Console.WriteLine(\"=== Bravely Default II Trainer ===\");\n            Console.WriteLine(\"1. Show current HP/MP/JP/Gold\");\n            Console.WriteLine(\"2. Set HP\");\n            Console.WriteLine(\"3. Set MP\");\n            Console.WriteLine(\"4. Set JP\");\n            Console.WriteLine(\"5. Set Gold\");\n            Console.WriteLine(\"6. Infinite HP (God Mode)\");\n            Console.WriteLine(\"7. Exit\");\n            Console.Write(\"Select option: \");\n        }\n\n        private void ShowCurrentValues()\n        {\n            try\n            {\n                int hp = _memoryEditor.GetCurrentHp();\n                int mp = _memoryEditor.GetCurrentMp();\n                int jp = _memoryEditor.GetCurrentJp();\n                int gold = _memoryEditor.GetCurrentGold();\n                Console.WriteLine($\"HP: {hp}\");\n                Console.WriteLine($\"MP: {mp}\");\n                Console.WriteLine($\"JP: {jp}\");\n                Console.WriteLine($\"Gold: {gold}\");\n            }\n            catch (Exception ex)\n            {\n                Console.WriteLine($\"Error reading values: {ex.Message}\");\n            }\n        }\n\n        private void SetHpMenu()\n        {\n            Console.Write(\"Enter new HP value: \");\n            if (int.TryParse(Console.ReadLine(), out int value))\n            {\n                _memoryEditor.SetHp(value);\n                Console.WriteLine(\"HP updated.\");\n            }\n            else\n            {\n                Console.WriteLine(\"Invalid number.\");\n            }\n        }\n\n        private void SetMpMenu()\n        {\n            Console.Write(\"Enter new MP value: \");\n            if (int.TryParse(Console.ReadLine(), out int value))\n            {\n                _memoryEditor.SetMp(value);\n                Console.WriteLine(\"MP updated.\");\n            }\n            else\n            {\n                Console.WriteLine(\"Invalid number.\");\n            }\n        }\n\n        private void SetJpMenu()\n        {\n            Console.Write(\"Enter new JP value: \");\n            if (int.TryParse(Console.ReadLine(), out int value))\n            {\n                _memoryEditor.SetJp(value);\n                Console.WriteLine(\"JP updated.\");\n            }\n            else\n            {\n                Console.WriteLine(\"Invalid number.\");\n            }\n        }\n\n        private void SetGoldMenu()\n        {\n            Console.Write(\"Enter new Gold value: \");\n            if (int.TryParse(Console.ReadLine(), out int value))\n            {\n                _memoryEditor.SetGold(value);\n                Console.WriteLine(\"Gold updated.\");\n            }\n            else\n            {\n                Console.WriteLine(\"Invalid number.\");\n            }\n        }\n    }\n}"},
    {"path": "bravely-default-2-trainer/tests/MemoryEditorTests.cs", "content": "using System;\nusing BravelyDefault2Trainer.Memory;\nusing Xunit;\nusing Moq;\n\nnamespace BravelyDefault2Trainer.Tests\n{\n    /// <summary>\n    /// Unit tests for MemoryEditor using a mocked ProcessManager.\n    /// Validates that memory read/write operations work as expected.\n    /// </summary>\n    public class MemoryEditorTests\n    {\n        [Fact]\n        public void GetCurrentHp_ReturnsExpectedValue()\n        {\n            // Arrange\n            var mockProcess = new Mock<ProcessManager>(\"TestProcess\");\n            byte[] expectedBytes = BitConverter.GetBytes(100);\n            mockProcess.Setup(p => p.ReadMemory(It.IsAny<int>(), 4)).Returns(expectedBytes);\n            var editor = new MemoryEditor(mockProcess.Object);\n\n            // Act\n            int hp = editor.GetCurrentHp();\n\n            // Assert\n            Assert.Equal(100, hp);\n        }\n\n        [Fact]\n        public void SetHp_WritesCorrectBytes()\n        {\n            // Arrange\n            var mockProcess = new Mock<ProcessManager>(\"TestProcess\");\n            // Assume max HP is 999\n            byte[] maxHpBytes = BitConverter.GetBytes(999);\n            mockProcess.Setup(p => p.ReadMemory(It.IsAny<int>(), 4)).Returns(maxHpBytes);\n            var editor = new MemoryEditor(mockProcess.Object);\n\n            byte[] expectedWrite = BitConverter.GetBytes(500);\n\n            // Act\n            editor.SetHp(500);\n\n            // Assert\n            mockProcess.Verify(p => p.WriteMemory(It.IsAny<int>(), expectedWrite), Times.Once);\n        }\n\n        [Fact]\n        public void SetHp_ClampsToMaxHp()\n        {\n            // Arrange\n            var mockProcess = new Mock<ProcessManager>(\"TestProcess\");\n            byte[] maxHpBytes = BitConverter.GetBytes(999);\n            mockProcess.Setup(p => p.ReadMemory(It.IsAny<int>(), 4)).Returns(maxHpBytes);\n            var editor = new MemoryEditor(mockProcess.Object);\n\n            byte[] expectedWrite = BitConverter.GetBytes(999);\n\n            // Act\n            editor.SetHp(1500);\n\n            // Assert\n            mockProcess.Verify(p => p.WriteMemory(It.IsAny<int>(), expectedWrite), Times.Once);\n        }\n\n        [Fact]\n        public void GetCurrentGold_ReturnsExpectedValue()\n        {\n            // Arrange\n            var mockProcess = new Mock<ProcessManager>(\"TestProcess\");\n            byte[] expectedBytes = BitConverter.GetBytes(50000);\n            mockProcess.Setup(p => p.ReadMemory(It.IsAny<int>(), 4)).Returns(expectedBytes);\n            var editor = new MemoryEditor(mockProcess.Object);\n\n
